import { useMemo, useState, useRef } from "react";
import { Skull, AlertTriangle, ShieldCheck, Shield, ShieldAlert, ShieldX } from "lucide-react";

const LABEL_COLOR = {
  Trustworthy: "#10b981",
  Neutral: "#a1a1aa",
  Suspicious: "#f59e0b",
  Flagged: "#ef4444",
};

const LABEL_META = {
  Trustworthy: { Icon: ShieldCheck, color: "text-emerald-400" },
  Neutral:     { Icon: Shield,      color: "text-zinc-400" },
  Suspicious:  { Icon: ShieldAlert, color: "text-amber-400" },
  Flagged:     { Icon: ShieldX,     color: "text-red-400" },
};

export function MarkupHistogram({ sellers, height = 140 }) {
  const buckets = useMemo(() => {
    const ranges = [
      { id: 0, min: -Infinity, max: -25,  color: "#10b981", grad: "from-emerald-500 to-emerald-400" },
      { id: 1, min: -25,       max: -10,  color: "#34d399", grad: "from-emerald-500/80 to-emerald-400/80" },
      { id: 2, min: -10,       max: 0,    color: "#6ee7b7", grad: "from-emerald-500/40 to-emerald-400/40" },
      { id: 3, min: 0,         max: 10,   color: "#a1a1aa", grad: "from-zinc-500/40 to-zinc-400/40" },
      { id: 4, min: 10,        max: 25,   color: "#fbbf24", grad: "from-amber-500/60 to-amber-400/60" },
      { id: 5, min: 25,        max: 50,   color: "#f97316", grad: "from-orange-500/80 to-orange-400/80" },
      { id: 6, min: 50,        max: 100,  color: "#f87171", grad: "from-red-500 to-red-400" },
      { id: 7, min: 100,       max: Infinity, color: "#dc2626", grad: "from-red-600 to-red-500" },
    ];
    const counts = ranges.map((r) => ({ ...r, count: 0 }));
    sellers.forEach((s) => {
      const m = s.avgMarkupPercent;
      const i = ranges.findIndex((r) => m >= r.min && m < r.max);
      if (i >= 0) counts[i].count++;
    });
    counts[0].label = "≤ -25%";
    counts[1].label = "-25%";
    counts[2].label = "-10%";
    counts[3].label = "0%";
    counts[4].label = "+10%";
    counts[5].label = "+25%";
    counts[6].label = "+50%";
    counts[7].label = ">100%";
    return counts;
  }, [sellers]);

  const max = Math.max(1, ...buckets.map((b) => b.count));
  const total = buckets.reduce((s, b) => s + b.count, 0);

  return (
    <div className="w-full">
      <div className="flex items-end justify-between gap-1.5" style={{ height: height + 18 }}>
        {buckets.map((b, i) => {
          const pct = (b.count / max) * 100;
          const isPeak = b.count === max && b.count > 0;
          return (
            <div key={i} className="flex-1 flex flex-col items-center group relative">
              <div className={`font-mono text-[10px] tabular mb-1 ${isPeak ? "text-white font-bold" : "text-zinc-500"}`}>
                {b.count > 0 ? b.count : ""}
              </div>
              <div
                className="w-full bg-white/[0.04] rounded-sm relative overflow-hidden"
                style={{ height }}
              >
                <div
                  className={`absolute bottom-0 left-0 right-0 bg-gradient-to-t ${b.grad} rounded-sm transition-all duration-700`}
                  style={{ height: `${pct}%` }}
                />
                {isPeak && (
                  <div className="absolute -top-1 left-1/2 -translate-x-1/2 w-0 h-0 border-l-4 border-r-4 border-t-4 border-l-transparent border-r-transparent border-t-emerald-400" />
                )}
              </div>
              <div className="absolute -top-1 left-1/2 -translate-x-1/2 -translate-y-full opacity-0 group-hover:opacity-100 pointer-events-none transition-opacity z-10 bg-bg-deep border border-white/20 rounded px-2 py-1 whitespace-nowrap font-mono text-[10px] text-zinc-200 shadow-xl">
                {b.label} · <span className="text-white">{b.count}</span> ({total > 0 ? ((b.count/total)*100).toFixed(0) : 0}%)
              </div>
            </div>
          );
        })}
      </div>
      <div className="mt-2 flex justify-between text-[9px] font-mono uppercase tracking-wider text-zinc-600">
        <span>Discount</span>
        <span className="text-zinc-700">0%</span>
        <span>Markup</span>
      </div>
    </div>
  );
}

export function ReputationMix({ sellers }) {
  const counts = useMemo(() => {
    const c = { Trustworthy: 0, Neutral: 0, Suspicious: 0, Flagged: 0 };
    sellers.forEach((s) => {
      if (s.isBlacklisted) { c.Flagged++; return; }
      const k = s.accuracyLabel && c[s.accuracyLabel] !== undefined ? s.accuracyLabel : "Neutral";
      c[k]++;
    });
    return c;
  }, [sellers]);

  const total = Object.values(counts).reduce((a, b) => a + b, 0) || 1;
  const order = ["Trustworthy", "Neutral", "Suspicious", "Flagged"];
  let cursor = 0;
  const stops = [];
  order.forEach((k) => {
    const pct = (counts[k] / total) * 100;
    if (pct > 0) stops.push(`${LABEL_COLOR[k]} ${cursor}% ${cursor + pct}%`);
    cursor += pct;
  });
  const gradient = stops.length > 0 ? `conic-gradient(${stops.join(", ")})` : "conic-gradient(#27272a 0% 100%)";

  return (
    <div className="flex items-center gap-5">
      <div className="relative shrink-0">
        <div className="w-28 h-28 rounded-full" style={{ background: gradient }} />
        <div className="absolute inset-3 rounded-full bg-bg-base flex flex-col items-center justify-center">
          <div className="font-heading text-2xl font-black tabular text-white">{total}</div>
          <div className="font-mono text-[9px] uppercase tracking-wider text-zinc-500">sellers</div>
        </div>
      </div>
      <div className="flex-1 space-y-1.5">
        {order.map((k) => {
          const { Icon, color } = LABEL_META[k];
          const n = counts[k];
          const pct = (n / total) * 100;
          return (
            <div key={k} className="flex items-center gap-2 text-[11px]">
              <div className="w-2.5 h-2.5 rounded-sm shrink-0" style={{ background: LABEL_COLOR[k] }} />
              <Icon className={`w-3 h-3 ${color}`} />
              <span className="text-zinc-300 flex-1">{k}</span>
              <span className="font-mono tabular text-zinc-400">{n}</span>
              <span className="font-mono tabular text-zinc-600 w-10 text-right">{pct.toFixed(0)}%</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export function WorstOffenders({ sellers, openSeller }) {
  const worst = useMemo(() => {
    return [...sellers]
      .filter((s) => !s.isBlacklisted && s.totalListings >= 3)
      .sort((a, b) => {
        if (b.overpricedRatio !== a.overpricedRatio) return b.overpricedRatio - a.overpricedRatio;
        return b.avgMarkupPercent - a.avgMarkupPercent;
      })
      .slice(0, 3);
  }, [sellers]);

  if (worst.length === 0) return null;

  return (
    <div className="bg-bg-deep border border-red-500/30 rounded-2xl p-5" data-testid="worst-offenders">
      <div className="flex items-center gap-2 mb-1">
        <Skull className="w-4 h-4 text-red-400" />
        <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-red-400">Avoid</span>
      </div>
      <p className="text-zinc-500 text-xs leading-relaxed mb-4">
        Highest overpriced ratio among non-blacklisted sellers with 3+ listings. Tap a row to inspect.
      </p>
      <div className="space-y-1.5">
        {worst.map((s, i) => {
          const isBedrock = s.identityKey?.startsWith("bedrock");
          return (
            <button
              key={s.key}
              data-testid={`worst-offender-${i}`}
              onClick={() => openSeller(s.name)}
              className="w-full flex items-center gap-3 bg-white/[0.02] border border-white/5 hover:border-red-500/40 rounded-lg p-2.5 transition-colors text-left group"
            >
              <span className="font-heading text-2xl font-black text-red-500/40 group-hover:text-red-400 w-6 tabular text-center">
                {i + 1}
              </span>
              <div className="shrink-0">
                {!isBedrock ? (
                  <img
                    src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(s.name)}`}
                    alt=""
                    width={32} height={32} loading="lazy"
                    className="w-8 h-8 rounded bg-white/[0.04] object-contain"
                    onError={(e) => { e.currentTarget.style.display = "none"; e.currentTarget.nextSibling.style.display = "grid"; }}
                  />
                ) : null}
                <div className="w-8 h-8 rounded bg-white/[0.04] border border-white/10 place-items-center text-zinc-500 font-mono text-[10px] uppercase"
                  style={{ display: isBedrock ? "grid" : "none" }}>
                  {s.name.slice(0, 2).toUpperCase()}
                </div>
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-heading text-sm font-bold truncate group-hover:text-red-300 transition-colors">{s.name}</div>
                <div className="font-mono text-[10px] text-zinc-500 uppercase tracking-wider">
                  {s.totalListings} listings · +{s.avgMarkupPercent.toFixed(0)}% markup
                </div>
              </div>
              <div className="text-right">
                <div className="font-mono text-sm font-bold tabular text-red-400">{s.overpricedRatio.toFixed(0)}%</div>
                <div className="font-mono text-[9px] uppercase tracking-wider text-zinc-600">overpriced</div>
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}

export function BlacklistSpotlight({ sellers, openSeller }) {
  const bl = useMemo(() => sellers.filter((s) => s.isBlacklisted).slice(0, 5), [sellers]);
  if (bl.length === 0) return null;
  return (
    <div className="bg-bg-deep border border-red-500/20 rounded-2xl p-5" data-testid="blacklist-spotlight">
      <div className="flex items-center gap-2 mb-1">
        <AlertTriangle className="w-4 h-4 text-red-400" />
        <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-red-400">Banned</span>
        <span className="ml-auto font-mono text-[10px] text-zinc-500 tabular">{bl.length} active</span>
      </div>
      <p className="text-zinc-500 text-xs leading-relaxed mb-3">
        These sellers are flagged by the community and excluded from search.
      </p>
      <div className="flex flex-wrap gap-1.5">
        {bl.map((s) => (
          <button
            key={s.key}
            onClick={() => openSeller(s.name)}
            className="inline-flex items-center gap-1.5 bg-red-500/10 border border-red-500/20 hover:border-red-500/40 rounded-full px-2.5 py-1 font-mono text-[11px] text-red-300 hover:text-red-200 transition-colors"
          >
            <ShieldX className="w-3 h-3" />
            <span className="truncate max-w-[10rem]">{s.name}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

export function MarkupScatter({ sellers, openSeller }) {
  const svgRef = useRef(null);
  const [hoverIdx, setHoverIdx] = useState(null);

  const points = useMemo(() => {
    const maxX = Math.max(10, ...sellers.map((s) => s.totalListings));
    const W = 480, H = 180;
    const padL = 36, padR = 12, padT = 12, padB = 28;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;
    return sellers.map((s) => {
      const x = padL + (s.totalListings / maxX) * innerW;
      const yClamped = Math.max(-50, Math.min(150, s.avgMarkupPercent));
      const y = padT + (1 - (yClamped + 50) / 200) * innerH;
      const color = s.isBlacklisted ? "#ef4444" : (LABEL_COLOR[s.accuracyLabel] || "#a1a1aa");
      const r = Math.min(6, 2 + Math.log2(Math.max(1, s.totalListings)) * 1.2);
      return { x, y, color, r, s };
    });
  }, [sellers]);

  const W = 480, H = 180;
  const padL = 36, padR = 12, padT = 12, padB = 28;
  const innerW = W - padL - padR;
  const innerH = H - padT - padB;
  const yToPx = (val) => padT + (1 - (val + 50) / 200) * innerH;
  const y0 = yToPx(0);
  const y10 = yToPx(10);
  const xMed = padL + innerW * 0.5;

  let tooltipStyle = {};
  let tooltipSeller = null;
  if (hoverIdx !== null && points[hoverIdx] && svgRef.current) {
    const svg = svgRef.current.getBoundingClientRect();
    const scaleX = svg.width / W;
    const scaleY = svg.height / H;
    const p = points[hoverIdx];
    let tx = svg.left + p.x * scaleX;
    const ty = svg.top + p.y * scaleY;
    tx = Math.max(140, Math.min(window.innerWidth - 140, tx));
    tooltipStyle = { left: `${tx}px`, top: `${ty}px` };
    tooltipSeller = p.s;
  }

  return (
    <div className="w-full markup-scatter relative">
      <svg ref={svgRef} viewBox={`0 0 ${W} ${H}`} className="w-full h-auto" data-testid="markup-scatter" style={{ overflow: "visible" }}>
        <defs>
          <linearGradient id="scatter-grid" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0" stopColor="var(--scatter-bg-start, #27272a)" />
            <stop offset="1" stopColor="var(--scatter-bg-end, #1f1f23)" />
          </linearGradient>
        </defs>
        <rect x={padL} y={padT} width={innerW} height={innerH} fill="var(--scatter-rect, #1f1f23)" rx="2" />

        {[50, 0, -50].map((v) => (
          <g key={v}>
            <line x1={padL} y1={yToPx(v)} x2={padL + innerW} y2={yToPx(v)} stroke="var(--scatter-line, #27272a)" strokeWidth="0.5" />
            <text x={padL - 6} y={yToPx(v) + 3} textAnchor="end" fontSize="9" fontFamily="ui-monospace" fill="#52525b">
              {v > 0 ? `+${v}` : v}%
            </text>
          </g>
        ))}

        <line x1={padL} y1={y0} x2={padL + innerW} y2={y0} stroke="#10b981" strokeWidth="1" strokeDasharray="3 3" opacity="0.6" />
        <text x={padL + innerW - 4} y={y0 - 4} textAnchor="end" fontSize="9" fontFamily="ui-monospace" fill="#10b981" opacity="0.8">median</text>
        <line x1={padL} y1={y10} x2={padL + innerW} y2={y10} stroke="#ef4444" strokeWidth="0.5" strokeDasharray="2 4" opacity="0.4" />
        <line x1={xMed} y1={padT} x2={xMed} y2={padT + innerH} stroke="var(--scatter-line-mid, #3f3f46)" strokeWidth="0.5" strokeDasharray="2 4" opacity="0.6" />

        <text x={padL + innerW / 2} y={H - 8} textAnchor="middle" fontSize="9" fontFamily="ui-monospace" fill="#52525b" letterSpacing="0.1em">LISTINGS →</text>
        <text x={10} y={padT + innerH / 2} textAnchor="middle" fontSize="9" fontFamily="ui-monospace" fill="#52525b" letterSpacing="0.1em" transform={`rotate(-90, 10, ${padT + innerH / 2})`}>MARKUP</text>

        {points.map((p, i) => (
          <circle
            key={i}
            cx={p.x} cy={p.y} r={p.r}
            fill={p.color} fillOpacity={hoverIdx === i ? "0.9" : "0.6"}
            stroke={p.color} strokeWidth={hoverIdx === i ? "1.5" : "0.5"}
            className={openSeller ? "cursor-pointer transition-all" : "transition-all"}
            onClick={openSeller ? () => openSeller(p.s.name) : undefined}
            onMouseEnter={() => setHoverIdx(i)}
            onMouseLeave={() => setHoverIdx(null)}
          />
        ))}
      </svg>

      {tooltipSeller && (
        <div
          className="fixed pointer-events-none z-[300] -translate-x-1/2 -translate-y-full"
          style={{ left: tooltipStyle.left, top: `calc(${tooltipStyle.top} - 12px)` }}
        >
          <div className="bg-bg-deep border border-white/15 rounded-md shadow-2xl px-3 py-2 text-left">
            <div className="font-heading text-sm font-bold text-white mb-1">{tooltipSeller.name}</div>
            <div className="font-mono text-[10px] text-zinc-400 space-y-0.5">
              <div><span className="text-zinc-500">Listings:</span> {tooltipSeller.totalListings}</div>
              <div><span className="text-zinc-500">Markup:</span> <span className={tooltipSeller.avgMarkupPercent > 15 ? "text-red-400" : tooltipSeller.avgMarkupPercent < -10 ? "text-emerald-400" : "text-white"}>{tooltipSeller.avgMarkupPercent > 0 ? "+" : ""}{tooltipSeller.avgMarkupPercent.toFixed(1)}%</span></div>
              <div><span className="text-zinc-500">Overpriced:</span> {tooltipSeller.overpricedRatio.toFixed(0)}%</div>
            </div>
          </div>
        </div>
      )}

      <div className="mt-3 flex flex-wrap gap-3 text-[10px] font-mono uppercase tracking-wider text-zinc-500">
        {Object.entries(LABEL_META).map(([k, v]) => (
          <span key={k} className="inline-flex items-center gap-1.5">
            <span className="w-2 h-2 rounded-full" style={{ background: LABEL_COLOR[k] }} />
            <v.Icon className={`w-3 h-3 ${v.color}`} />
            {k}
          </span>
        ))}
      </div>
    </div>
  );
}